-- Auto-generated structured rules from NY Medicaid Dental 2026 PDF
create schema if not exists coding_agent;

create table if not exists coding_agent.cdt_payer_rules_structured ( id bigserial primary key, code text not null references coding_agent.cdt_code_master(code) on delete cascade, payer_name text not null, rule_type text not null, rule_text text not null, fee numeric(10,2), age_min int, age_max int, frequency_count int, frequency_period_months int, requires_prior_auth boolean not null default false, requires_report boolean not null default false, allowed_pos_codes text[], restriction_exception_codes text[], not_billable_with_codes text[], section_label text, source_page int, conditions jsonb not null default '{}'::jsonb, source_id bigint references coding_agent.rule_sources(id) on delete cascade, created_at timestamptz not null default now(), unique (code, payer_name));

create index if not exists cdt_rules_structured_code_idx on coding_agent.cdt_payer_rules_structured(code);
create index if not exists cdt_rules_structured_type_idx on coding_agent.cdt_payer_rules_structured(rule_type);
create index if not exists cdt_rules_structured_pa_idx on coding_agent.cdt_payer_rules_structured(requires_prior_auth);

with src as (
  select id from coding_agent.rule_sources where source_slug = 'nys_medicaid_dental_2026'
)
on conflict (code, payer_name) do update set rule_type = excluded.rule_type, rule_text = excluded.rule_text, fee = excluded.fee, age_min = excluded.age_min, age_max = excluded.age_max, frequency_count = excluded.frequency_count, frequency_period_months = excluded.frequency_period_months, requires_prior_auth = excluded.requires_prior_auth, requires_report = excluded.requires_report, allowed_pos_codes = excluded.allowed_pos_codes, restriction_exception_codes = excluded.restriction_exception_codes, not_billable_with_codes = excluded.not_billable_with_codes, section_label = excluded.section_label, source_page = excluded.source_page, conditions = excluded.conditions, source_id = excluded.source_id;

create or replace function coding_agent.match_cdt_rule( p_code text, p_payer_name text, p_age int default null, p_pos_code text default null, p_check_pa boolean default false) returns table ( code text, payer_name text, rule_type text, rule_text text, fee numeric, requires_prior_auth boolean, requires_report boolean, allowed_pos_codes text[], not_billable_with_codes text[]) language sql stable as $$  select    r.code,    r.payer_name,    r.rule_type,    r.rule_text,    r.fee,    r.requires_prior_auth,    r.requires_report,    r.allowed_pos_codes,    r.not_billable_with_codes  from coding_agent.cdt_payer_rules_structured r  where r.code = p_code    and lower(r.payer_name) = lower(p_payer_name)    and (p_age is null or (coalesce(r.age_min, -1) <= p_age and coalesce(r.age_max, 999) >= p_age))    and (p_pos_code is null or r.allowed_pos_codes is null or p_pos_code = any(r.allowed_pos_codes))    and (not p_check_pa or r.requires_prior_auth = true);$$;

grant select on coding_agent.cdt_payer_rules_structured to service_role, authenticated, anon;
grant execute on function coding_agent.match_cdt_rule(text, text, int, text, boolean) to service_role, authenticated, anon;
