('D0330', 'New York State Medicaid', 'coverage_rule', 'D0330 Panoramic radiographic image Reimbursable every three years if clinically indicated. Postoperative panoramic images are reimbursable for post-surgical evaluation of fractures, dislocations, orthognathic surgery, osteomyelitis, or removal of unusually large and/or complex cysts or neoplasms. Panoramic radiographic images are not required or reimbursable for post orthodontic documentation. Panoramic images are not reimbursable when an intraoral complete series or panoramic image has been taken within three years, except for the diagnosis of a new condition (e.g., traumatic injury, orthodontic evaluation).', 35.35, null, null, null, null, false, false, null, null, null, 'I. DIAGNOSTIC D0100-D0999', 27, '{"frequency_rule": null, "parser": "heuristic_v1", "source_slug": "nys_medicaid_dental_2026"}'::jsonb, (select id from src)),
('D0340', 'New York State Medicaid', 'coverage_rule', 'Reimbursable every three years if clinically indicated. Reimbursement is limited to enrolled orthodontists or oral and maxillofacial surgeons for the diagnosing and treatment of a physically handicapping malocclusion. Cephalometric images are not required by the DOH for routine post -orthodontic documentation and are not routinely reimbursable.', 55.55, null, null, null, null, false, false, null, null, null, 'I. DIAGNOSTIC D0100-D0999', 27, '{"frequency_rule": null, "parser": "heuristic_v1", "source_slug": "nys_medicaid_dental_2026"}'::jsonb, (select id from src)),
('D0350', 'New York State Medicaid', 'coverage_rule', 'D0350 2D Oral/Facial Photographic Image; and PA Attachments Addition of Language and Links: Description of 2D Oral/Facial Photographic Image; and Instructions for Adding Attachment to a PA D0350 2D oral/facial photographic image obtained intra-orally or extra-orally Photographs are reimbursable when associated with procedures described under sections: • V. PERIODONTICS, limited to gingivectomy or gingivoplasty, procedure codes D4210, D4211, and clinical crown lengthening, procedure code D4249 • VIII. ORAL AND MAXILLOFACIAL SURGERY , limited to frenectomy, frenuloplasty, and frenulectomy, procedure codes D7961, D7962 • XI. • There is no professional reimbursement for facility place of service. For treatment not involving implants or implant-related services, a panoramic radiograph (D0330) or similar film, along with documentation of medical necessity, must be submitted with requests for prior approval. Approval is limited to those cases demonstrating significant risk for a complication such as nerve injury or jaw fracture, as well as pathology or trauma workups.', 12.12, null, null, null, null, false, false, null, null, null, 'I. DIAGNOSTIC D0100-D0999', 6, '{"frequency_rule": null, "parser": "heuristic_v1", "source_slug": "nys_medicaid_dental_2026"}'::jsonb, (select id from src)),
