('D4249', 'New York State Medicaid', 'prior_auth', 'D4249 Clinical Crown Lengthening – hard tissue (PA REQUIRED) Crown lengthening requires reflection of a full thickness flap and removal of bone, altering the crown to root ratio. Crown lengthening is reimbursable solely when associated with medically necessary crown or root canal procedure. If the need for crown lengthening is discovered during a procedure, then providers should refer to Prior Approval Change Request information.', 75.00, null, null, null, null, true, false, null, null, null, 'V. PERIODONTICS D4000-D4999', 37, '{"frequency_rule": null, "parser": "heuristic_v1", "source_slug": "nys_medicaid_dental_2026"}'::jsonb, (select id from src)),
('D4273', 'New York State Medicaid', 'prior_auth', 'D4273 Autogenous connective tissue graft procedure (including donor and recipient surgical sites) first tooth, implant or edentulous tooth position in graft (TOOTH) (PA REQUIRED) (POST OPERATIVE CARE: 14 DAYS) There are two surgical sites. The recipient site utilizes a split thickness incision, retaining the overlapping flap of gingiva and/or mucosa. The connective tissue is dissected from a separate donor site leaving an epithelialized flap for closure. $303.00', 303.00, null, null, null, null, true, false, null, null, null, 'VIII. IMPLANT SERVICES D6000-D6199', 46, '{"frequency_rule": null, "parser": "heuristic_v1", "source_slug": "nys_medicaid_dental_2026"}'::jsonb, (select id from src)),
