('D6199', 'New York State Medicaid', 'prior_auth', 'Prior approval is required for orthodontic services, implants, and specified implant-related services. Services Not Within the Scope of the Medicaid Program These services include but are not limited to: • Fixed bridgework, except for cleft palate stabilization, or when a removable prosthesis would be contraindicated. • Placement of sealants for members under 5 or over 15 years of age. Services Which Do Not Meet Existing Standards of Professional Practice Are Not Reimbursable These services include but are not limited to: • Partial dentures provided prior to completion of all Phase I restorative treatment which includes necessary extractions, removal of all decay and placement of permanent restorations. Published “frequency limits” are general reference points on the anticipated frequency for that procedure. Actual frequency must be based on the clinical needs of the individual member.', null, null, null, null, null, true, true, null, '{81,95}'::text[], '{D0120,D0145,D0150,D0210,D0330,D0999,D1510,D1516,D1517,D1575,D2710,D2792,D2794,D2952,D2999,D3310,D3348,D3999,D4245,D4273,D4275,D4277,D4278,D4283,D4285,D5110,D5120,D5211,D5214,D5225,D5226,D5510,D5660,D5710,D5721,D5750,D5761,D5820,D5821,D5899,D5911,D5988,D5999,D6052,D6067,D6090,D6091,D6094,D6106,D6107,D6110,D6113,D6210,D6252,D6545,D6792,D6794,D6999,D8660,D8680,D8999,D9944,D9945,D9946,D9999}'::text[], 'VIII. IMPLANT SERVICES D6000-D6199', 11, '{"frequency_rule": null, "parser": "heuristic_v1", "source_slug": "nys_medicaid_dental_2026"}'::jsonb, (select id from src)),
