('D8660', 'New York State Medicaid', 'coverage_rule', 'D8660 Pre-orthodontic treatment examination to monitor growth and development Periodic observation of patient dentition, at intervals established by the dentist, to determine when orthodontic treatment should begin. Diagnostic procedures are documented separately. Orthodontist specialty designation required. May not be reimbursed in conjunction with other examination codes. Cannot be reimbursed after active orthodontic treatment has begun. $29.29', 29.29, null, null, null, null, false, false, null, null, null, 'XI. ORTHODONTICS D8000-D8999', 62, '{"frequency_rule": null, "parser": "heuristic_v1", "source_slug": "nys_medicaid_dental_2026"}'::jsonb, (select id from src)),
