('D9243', 'New York State Medicaid', 'billing_exclusion', 'D9243 Administration of moderate sedation – intravenous – each subsequent 15-minute increment, or any portion thereof Requires Appropriate NYSED certificate $76.76 Current Dental terminology (CDT) code D9230, D9244, D9245, and D9246 are reimbursable for members/enrollees through 20 years of age (inclusive) in conjunction with covered dental services, with documentation of the patient-specific diagnosis or behavior indicating clinical necessity. Codes D9230, D9244, D9245, and D9246" are not billable when another billable method of anesthesia/analgesia/sedation (i.e., "D9222", "D9223", "D9239", and "D9243") is used during an encounter. For members/enrollees 21 years of age and older, D9230, D9244, D9245, and D9246 are only approvable for those members/enrollees identified with a Restriction Exception code of RE “81” (Traumatic Brain Injury Eligible) or RE “95” [Office of Persons with Developmental Disabilities (OPWDD)].', 76.76, null, null, null, null, false, false, null, '{81,95}'::text[], '{D9222,D9223,D9230,D9239,D9244,D9245,D9246}'::text[], 'XII. ADJUNCTIVE GENERAL SERVICES D9000-D9999', 64, '{"frequency_rule": null, "parser": "heuristic_v1", "source_slug": "nys_medicaid_dental_2026"}'::jsonb, (select id from src)),
('D9244', 'New York State Medicaid', 'coverage_rule', 'D9244, D9245, and D9246 Administration of Sedation New Procedure Codes Also added to Appendix I: IDD Population D9244 In-office administration of minimal sedation- single drug – enteral In-office administration of a drug, as a single or divided dose, to achieve the desired clinical effect, not to exceed the FDA maximum recommended dose (MRD) for unmonitored home use. The single drug may be administered with or without co-administration of nitrous oxide. $25.00 D9244 In-office administration of minimal sedation- single drug – enteral No No', 25.00, null, null, null, null, false, false, null, null, null, 'XII. ADJUNCTIVE GENERAL SERVICES D9000-D9999', 7, '{"frequency_rule": null, "parser": "heuristic_v1", "source_slug": "nys_medicaid_dental_2026"}'::jsonb, (select id from src)),
