('D9430', 'New York State Medicaid', 'documentation_requirement', 'D9430 Office visit for observation (during regularly scheduled hours) – no other services performed (REPORT NEEDED) The provider must be enrolled in one of the dental specialty areas recognized by the NYS Medicaid program. Reimbursement includes the prescribing of medications and is limited to two instances per clinical episode. This is a “stand-alone” procedure and cannot be billed on the same date of service with any other procedure code. Limited to four (4) instances per year per member. This is a “stand-alone” procedure and cannot be billed on the same date of service with any other procedure code. Limited to four (4) instances per year per member.', 20.20, null, null, null, null, false, true, null, '{81,95}'::text[], null, 'XII. ADJUNCTIVE GENERAL SERVICES D9000-D9999', 66, '{"frequency_rule": null, "parser": "heuristic_v1", "source_slug": "nys_medicaid_dental_2026"}'::jsonb, (select id from src)),
