('D9996', 'New York State Medicaid', 'coverage_rule', 'D9996 Teledentistry – asynchronous information stored and forwarded to dentist for subsequent review Reported in addition to other procedures (e.g., diagnostic) delivered to the patient on the date of service. • Procedure code D9996 may be used by the provider at the distant site; • Must be reported on claim line #1; • Report all services rendered on subsequent lines; • There is no reimbursement for procedure code D9996. $0.00 Q3014 Telehealth originating site facility fee • Procedure code Q3014 may be used by the provider at the originating site; • Must be reported on claim line #1; • Report any additional services rendered on subsequent lines; For information about billing code Q3014, please refer to the New York State Medicaid Fee-for- Service Provider Telehealth Policy Manual. $28.04', 0.00, null, null, null, null, false, false, null, null, null, 'XII. ADJUNCTIVE GENERAL SERVICES D9000-D9999', 69, '{"frequency_rule": null, "parser": "heuristic_v1", "source_slug": "nys_medicaid_dental_2026"}'::jsonb, (select id from src)),
('D9997', 'New York State Medicaid', 'billing_exclusion', 'For purposes of the NYS Medicaid program, billing of this code is limited to individuals who receive ongoing services from community programs operated or certified by the New York State Office for People with Developmental Disabilities (OPWDD) with a Restriction Exception code of RE 81 (“TBI Eligible”) or RE 95 (“OPWDD/Managed Care Exemption”). • Not billable in conjunction with D9430 or procedures performed under deep sedation/general anesthesia. • Not billable as a “stand-alone” procedure; another clinical service must be provided on the same date. For purposes of the NYS Medicaid program, billing of this code is limited to individuals who receive ongoing services from community programs operated or certified by the New York State Office for People with Developmental Disabilities (OPWDD) with a Restriction Exception code of RE 81 (“TBI Eligible”) or RE 95 (“OPWDD/Managed Care Exemption”). • Not billable in conjunction with D9430 or procedures performed under deep sedation/general anesthesia. • Not billable as a “stand -alone” procedure; another clinical service must be provided on the same date.', 29.29, null, null, null, null, false, false, null, '{81,95}'::text[], '{D9430}'::text[], 'XII. ADJUNCTIVE GENERAL SERVICES D9000-D9999', 69, '{"frequency_rule": null, "parser": "heuristic_v1", "source_slug": "nys_medicaid_dental_2026"}'::jsonb, (select id from src)),
